def gen(rng, size):
    n = max(2, size)
    a, b = [], []
    ca = cb = 0
    for _ in range(n):
        ca += rng.randint(1, 4)
        cb += rng.randint(1, 4)
        a.append(ca)
        b.append(cb)
    for i in range(n):
        if rng.random() < 0.5:
            a[i], b[i] = b[i], a[i]
    return [a, b]

