class Solution:
    def minSwap(self, nums1, nums2):
        import sys
        from functools import lru_cache
        sys.setrecursionlimit(300000)
        n = len(nums1)
        INF = float('inf')
        @lru_cache(None)
        def f(i, prev1, prev2):
            if i == n:
                return 0
            best = INF
            # keep
            if nums1[i] > prev1 and nums2[i] > prev2:
                best = min(best, f(i + 1, nums1[i], nums2[i]))
            # swap
            if nums2[i] > prev1 and nums1[i] > prev2:
                best = min(best, 1 + f(i + 1, nums2[i], nums1[i]))
            return best
        return f(0, -1, -1)

